 43→// Suppress Vite's CSS preload errors in the Chrome extension content script context.
 44→// Dynamic imports (e.g., mermaid) trigger Vite's __vitePreload helper which tries to
 45→// create <link> elements with paths like "/assets/foo.css". In a content script, these
 46→// resolve to the web page origin (e.g., https://gemini.google.com/assets/foo.css)
 47→// instead of the extension, causing false "Unable to preload CSS" errors.
 48→// The CSS is already injected via contentStyle.css, so these preloads are unnecessary.
 49→window.addEventListener('vite:preloadError', (event) => {
 50→  event.preventDefault();
 51→});
 52→
 53→/**
 54→ * Staggered initialization to prevent "thundering herd" problem when multiple tabs
 55→ * are restored simultaneously (e.g., after browser restart).
 56→ *
 57→ * Background tabs get a random delay (3-8s) to distribute initialization load.
 58→ * Foreground tabs initialize immediately for good UX.
 59→ *
 60→ * This prevents triggering Google's rate limiting when restoring sessions with
 61→ * many Gemini tabs containing long conversations.
 62→ */
 63→
 64→// Initialization delay constants (in milliseconds)
 65→const HEAVY_FEATURE_INIT_DELAY = 100; // For resource-intensive features (Timeline, Folder)
 66→const LIGHT_FEATURE_INIT_DELAY = 50; // For lightweight features
 67→const BACKGROUND_TAB_MIN_DELAY = 3000; // Minimum delay for background tabs
 68→const BACKGROUND_TAB_MAX_DELAY = 8000; // Maximum delay for background tabs (3000 + 5000)
 69→
 70→let initialized = false;
 71→let initializationTimer: number | null = null;
 72→let folderManagerInstance: Awaited<ReturnType<typeof startFolderManager>> | null = null;
 73→
 74→let promptManagerInstance: Awaited<ReturnType<typeof startPromptManager>> | null = null;
 75→let quoteReplyCleanup: (() => void) | null = null;
 76→let sendBehaviorCleanup: (() => void) | null = null;
 77→let forkCleanup: (() => void) | null = null;
 78→
 79→async function isForkFeatureEnabled(): Promise<boolean> {
 80→  try {
 81→    const result = await chrome.storage?.sync?.get({ [StorageKeys.FORK_ENABLED]: false });
 82→    return isForkFeatureEnabledValue(result?.[StorageKeys.FORK_ENABLED]);
 83→  } catch {
 84→    return false;
 85→  }
 86→}
 87→
 88→/**
 89→ * Check if current hostname matches any custom websites
 90→ */
 91→async function isCustomWebsite(): Promise<boolean> {
 92→  try {
 93→    const result = await chrome.storage?.sync?.get({ gvPromptCustomWebsites: [] });
 94→    const customWebsites = Array.isArray(result?.gvPromptCustomWebsites)
 95→      ? result.gvPromptCustomWebsites
 96→      : [];
 97→
 98→    // Normalize current hostname
 99→    const currentHost = location.hostname.toLowerCase().replace(/^www\./, '');
100→
101→    console.log('[Gemini Voyager] Checking custom websites:', {
102→      currentHost,
103→      customWebsites,
104→      hostname: location.hostname,
105→    });
106→
107→    const isCustom = customWebsites.some((website: string) => {
108→      const normalizedWebsite = website.toLowerCase().replace(/^www\./, '');
109→      const matches =
110→        currentHost === normalizedWebsite || currentHost.endsWith('.' + normalizedWebsite);
111→      console.log('[Gemini Voyager] Comparing:', { currentHost, normalizedWebsite, matches });
112→      return matches;
113→    });
114→
115→    console.log('[Gemini Voyager] Is custom website:', isCustom);
116→    return isCustom;
117→  } catch (e) {
118→    if (isExtensionContextInvalidatedError(e)) {
119→      return false;
120→    }
121→    console.error('[Gemini Voyager] Error checking custom websites:', e);
122→    return false;
123→  }
124→}
