251→      void startUpsellHider();
252→      await delay(LIGHT_FEATURE_INIT_DELAY);
253→
254→      // Markdown Patcher - fixes broken bold tags due to HTML injection
255→      startMarkdownPatcher();
256→      await delay(LIGHT_FEATURE_INIT_DELAY);
257→
258→      // Default Model Manager
259→      DefaultModelManager.getInstance().init();
260→      await delay(LIGHT_FEATURE_INIT_DELAY);
261→
262→      startExportButton();
263→      await delay(LIGHT_FEATURE_INIT_DELAY);
264→
265→      if (await isForkFeatureEnabled()) {
266→        forkCleanup = startFork();
267→        await delay(LIGHT_FEATURE_INIT_DELAY);
268→      }
269→
270→      startChangelog();
271→      await delay(LIGHT_FEATURE_INIT_DELAY);
272→    }
273→
274→    if (
275→      location.hostname === 'gemini.google.com' ||
276→      location.hostname === 'aistudio.google.com' ||
277→      location.hostname === 'aistudio.google.cn'
278→    ) {
279→      promptManagerInstance = await startPromptManager();
280→      await delay(HEAVY_FEATURE_INIT_DELAY);
281→    }
282→
283→    if (location.hostname === 'gemini.google.com') {
284→      // Initialize Mermaid rendering (lightweight)
285→      startMermaid();
286→      await delay(LIGHT_FEATURE_INIT_DELAY);
287→    }
288→
289→    if (location.hostname === 'aistudio.google.com' || location.hostname === 'aistudio.google.cn') {
290→      // Check if user has disabled Voyager on AI Studio
291→      const aiStudioEnabled = await new Promise<boolean>((resolve) => {
292→        try {
293→          chrome.storage?.sync?.get({ [StorageKeys.GV_AISTUDIO_ENABLED]: true }, (res) =>
294→            resolve(res?.[StorageKeys.GV_AISTUDIO_ENABLED] !== false),
295→          );
296→        } catch {
297→          resolve(true);
298→        }
299→      });
300→
301→      if (!aiStudioEnabled) {
302→        console.log('[Gemini Voyager] AI Studio features disabled by user');
303→        return;
304→      }
305→
306→      startAIStudioFolderManager();
307→      await delay(HEAVY_FEATURE_INIT_DELAY);
308→
309→      startFolderSpacingAdjuster('aistudio');
310→      await delay(LIGHT_FEATURE_INIT_DELAY);
311→
312→      // Formula copy support for AI Studio
313→      startFormulaCopy();
314→      await delay(LIGHT_FEATURE_INIT_DELAY);
315→    }
316→  } catch (e) {
317→    if (isExtensionContextInvalidatedError(e)) {
318→      return;
319→    }
320→    console.error('[Gemini Voyager] Initialization error:', e);
321→  }
322→}
323→
324→/**
325→ * Determine initialization delay based on tab visibility
326→ */
327→function getInitializationDelay(): number {
328→  // Check if tab is currently visible
329→  const isVisible = document.visibilityState === 'visible';
330→
331→  if (isVisible) {
332→    // Foreground tab: initialize immediately for good UX
333→    console.log('[Gemini Voyager] Foreground tab detected, initializing immediately');
334→    return 0;
335→  } else {
336→    // Background tab: add random delay to distribute load across multiple tabs
337→    const randomRange = BACKGROUND_TAB_MAX_DELAY - BACKGROUND_TAB_MIN_DELAY;
338→    const randomDelay = BACKGROUND_TAB_MIN_DELAY + Math.random() * randomRange;
339→    console.log(
340→      `[Gemini Voyager] Background tab detected, delaying initialization by ${Math.round(randomDelay)}ms`,
341→    );
342→    return randomDelay;
343→  }
344→}
345→
346→/**
347→ * Handle tab visibility changes
348→ */
349→function handleVisibilityChange(): void {
350→  if (document.visibilityState === 'visible' && !initialized) {
351→    // Tab became visible before initialization completed
352→    // Cancel any pending delayed initialization and start immediately
353→    if (initializationTimer !== null) {
354→      clearTimeout(initializationTimer);
355→      initializationTimer = null;
356→      console.log('[Gemini Voyager] Tab became visible, initializing immediately');
357→    }
358→    initializeFeatures();
359→  }
360→}
361→
362→// Main initialization logic
363→(function () {
364→  try {
365→    if (!hasValidExtensionContext()) return;
366→
367→    const onUnhandledRejection = (event: PromiseRejectionEvent) => {
368→      if (isExtensionContextInvalidatedError(event.reason)) {
369→        event.preventDefault();
370→      }
371→    };
372→    const onWindowError = (event: ErrorEvent) => {
373→      if (isExtensionContextInvalidatedError(event.error ?? event.message)) {
374→        event.preventDefault();
375→      }
376→    };
377→    window.addEventListener('unhandledrejection', onUnhandledRejection);
378→    window.addEventListener('error', onWindowError);
379→    const onStorageChanged = (
380→      changes: Record<string, chrome.storage.StorageChange>,
381→      areaName: string,
382→    ) => {
383→      if (
384→        (areaName !== 'sync' && areaName !== 'local') ||
385→        location.hostname !== 'gemini.google.com'
386→      ) {
387→        return;
388→      }
389→
390→      const forkSetting = changes[StorageKeys.FORK_ENABLED];
391→      if (!forkSetting) return;
392→
393→      const enabled = isForkFeatureEnabledValue(forkSetting.newValue);
394→      if (enabled) {
395→        if (!forkCleanup) {
396→          forkCleanup = startFork();
397→        }
398→      } else if (forkCleanup) {
399→        forkCleanup();
400→        forkCleanup = null;
401→      }
402→    };
403→
404→    // Quick check: only run on supported websites
405→    const hostname = location.hostname.toLowerCase();
406→    const isSupportedSite =
407→      hostname.includes('gemini.google.com') ||
408→      hostname.includes('business.gemini.google') ||
409→      hostname.includes('aistudio.google.com') ||
410→      hostname.includes('aistudio.google.cn');
411→
412→    // Initialize KaTeX configuration early to suppress Unicode warnings
413→    // This must run before any formulas are rendered on the page
414→    if (isSupportedSite) {
415→      initKaTeXConfig();
416→      // Initialize i18n early to ensure translations are available
417→      initI18n().catch((e) => console.error('[Gemini Voyager] i18n init error:', e));
418→    }
419→
420→    // If not a known site, check if it's a custom website (async)
421→    if (!isSupportedSite) {
422→      // For unknown sites, check storage asynchronously
423→      chrome.storage?.sync?.get({ gvPromptCustomWebsites: [] }, (result) => {
424→        const customWebsites = Array.isArray(result?.gvPromptCustomWebsites)
425→          ? result.gvPromptCustomWebsites
426→          : [];
427→        const currentHost = hostname.replace(/^www\./, '');
428→
429→        const isCustomSite = customWebsites.some((website: string) => {
430→          const normalizedWebsite = website.toLowerCase().replace(/^www\./, '');
431→          return currentHost === normalizedWebsite || currentHost.endsWith('.' + normalizedWebsite);
432→        });
433→
434→        if (isCustomSite) {
435→          console.log('[Gemini Voyager] Custom website detected:', hostname);
436→          initializeFeatures();
437→        } else {
438→          // Not a supported site, exit early
439→          console.log('[Gemini Voyager] Not a supported website, skipping initialization');
440→        }
441→      });
442→      return;
443→    }
444→    chrome.storage?.onChanged?.addListener(onStorageChanged);
445→
446→    const delay = getInitializationDelay();
447→
448→    if (delay === 0) {
449→      // Immediate initialization for foreground tabs
450→      initializeFeatures();
451→    } else {
452→      // Delayed initialization for background tabs
453→      initializationTimer = window.setTimeout(() => {
454→        initializationTimer = null;
455→        initializeFeatures();
456→      }, delay);
457→    }
458→
459→    // Listen for visibility changes to handle tab switching
460→    document.addEventListener('visibilitychange', handleVisibilityChange);
461→
462→    // Setup cleanup on page unload to prevent memory leaks
463→    window.addEventListener('beforeunload', () => {
464→      try {
465→        window.removeEventListener('unhandledrejection', onUnhandledRejection);
466→        window.removeEventListener('error', onWindowError);
467→        if (folderManagerInstance) {
468→          folderManagerInstance.destroy();
469→          folderManagerInstance = null;
470→        }
471→        if (promptManagerInstance) {
472→          promptManagerInstance.destroy();
473→          promptManagerInstance = null;
474→        }
475→        if (quoteReplyCleanup) {
476→          quoteReplyCleanup();
477→          quoteReplyCleanup = null;
478→        }
479→        if (sendBehaviorCleanup) {
480→          sendBehaviorCleanup();
481→          sendBehaviorCleanup = null;
482→        }
483→        if (forkCleanup) {
484→          forkCleanup();
485→          forkCleanup = null;
486→        }
487→        chrome.storage?.onChanged?.removeListener(onStorageChanged);
488→      } catch (e) {
489→        if (isExtensionContextInvalidatedError(e)) {
490→          return;
491→        }
492→        console.error('[Gemini Voyager] Cleanup error:', e);
493→      }
494→    });
495→  } catch (e) {
496→    if (isExtensionContextInvalidatedError(e)) {
497→      return;
498→    }
499→    console.error('[Gemini Voyager] Fatal initialization error:', e);
500→  }
501→})();
502→

