        {/* Cloud Sync - First priority - Hidden on Safari due to API limitations */}
        {!isSafariBrowser && <CloudSyncSettings />}
        {/* Context Sync */}
        <ContextSyncSettings />
        {/* Timeline Options */}
        <Card className="p-4 transition-all hover:shadow-md">
